s($,"bbi","aFD",()=>{var q="\u0110\u1ea3o An To\xe0n",p=null,o="\u0110\u1ea3o T\xecnh B\u1ea1n",n="\u0110\u1ea3o Tr\u01b0\u1eddng H\u1ecdc"
return A.b([A.pB("B\xe9 ngoan l\u1eafm! G\u1eb7p \u0111\u1ed3 v\u1eadt nh\u1ecf l\u1ea1 r\u01a1i tr\xean s\xe0n, h\xe3y \u0111\u01b0a ngay cho ng\u01b0\u1eddi l\u1edbn nh\xe9.","assets/videos/Safety_smallitems/lesson1-correct.mp4","B\xe9 \u0111\u01b0a v\u1eadt nh\u1ecf cho m\u1eb9 \u0111\u1ec3 m\u1eb9 c\u1ea5t v\xe0o t\u1ee7 cao. Reward: B\xe9 kh\xf4ng b\u1ecf v\u1eadt l\u1ea1 v\xe0o mi\u1ec7ng! +1 Safety Star.","B\xe9 h\u1ecdc c\xe1ch nh\u1eadn bi\u1ebft v\u1eadt nh\u1ecf l\u1ea1, kh\xf4ng b\u1ecf v\xe0o mi\u1ec7ng v\xe0 \u0111\u01b0a cho ng\u01b0\u1eddi l\u1edbn.","assets/videos/Safety_smallitems/lesson1-intro.mp4",1,q,"B\u1ecf v\xe0o mi\u1ec7ng \u0111\u1ec3 n\u1ebfm th\u1eed xem sao.","assets/images/flashCard/Safety_smallitems/wrong.webp","assets/voices/Safety_smallitems/choice-put-mouth.mp3","Mang \u0111\u1ebfn \u0111\u01b0a cho b\u1ed1 m\u1eb9 v\xe0 n\xf3i con nh\u1eb7t \u0111\u01b0\u1ee3c c\xe1i n\xe0y.","assets/images/flashCard/Safety_smallitems/Correct.webp","assets/voices/Safety_smallitems/choice-ask-adult.mp3","N\u1ebfu con nh\u1eb7t \u0111\u01b0\u1ee3c m\u1ed9t vi\xean bi ho\u1eb7c v\u1eadt nh\u1ecf l\u1ea1 tr\xean s\xe0n, con n\xean l\xe0m g\xec?","Con n\xean l\xe0m g\xec khi nh\u1eb7t \u0111\u01b0\u1ee3c v\u1eadt tr\xf2n nh\u1ecf l\u1ea5p l\xe1nh tr\xean s\xe0n?","assets/voices/Safety_smallitems/question.mp3","Tr\u1ebb nh\u1ecf kh\xe1m ph\xe1 th\u1ebf gi\u1edbi b\u1eb1ng c\xe1ch ng\u1eadm \u0111\u1ed3 v\u1eadt. H\xe3y gi\u1eef c\xe1c lo\u1ea1i pin n\xfat, nam ch\xe2m ho\u1eb7c nh\u1eefng d\u1ecb v\u1eadt xa t\u1ea7m tay b\xe9.","B\xe9 \u0111ang ch\u01a1i x\u1ebfp h\xecnh th\xec m\u1ed9t vi\xean bi \u0111\u1ed3 ch\u01a1i h\xecnh tr\xf2n l\u1ea5p l\xe1nh v\u0103ng ra kh\u1ecfi m\xf4 h\xecnh.",101,"Nh\u1eadn bi\u1ebft \u0111\u1ed3 v\u1eadt nguy hi\u1ec3m c\xf3 nguy c\u01a1 g\xe2y h\xf3c/nu\u1ed1t ph\u1ea3i; bi\u1ebft ph\xe2n bi\u1ec7t \u0111\u1ed3 \u0103n \u0111\u01b0\u1ee3c v\xe0 kh\xf4ng \u0103n \u0111\u01b0\u1ee3c.","An to\xe0n d\u1ecb v\u1eadt","B\xe0i 1: V\u1eadt tr\xf2n l\u1ea5p l\xe1nh","Nguy hi\u1ec3m qu\xe1! \u0110\u1ed3 v\u1eadt nh\u1ecf kh\xf4ng ph\u1ea3i \u0111\u1ed3 \u0103n v\xe0 c\xf3 th\u1ec3 l\xe0m b\xe9 b\u1ecb h\xf3c.","assets/videos/Safety_smallitems/lesson1-wrong.mp4","\u0110\u1ed3 v\u1eadt nh\u1ecf kh\xf4ng ph\u1ea3i \u0111\u1ed3 \u0103n, b\u1ecf v\xe0o mi\u1ec7ng s\u1ebd g\xe2y h\xf3c, ngh\u1eb9t th\u1edf v\xe0 l\xe0m \u0111au b\u1ee5ng."),A.pB("Hoan h\xf4 b\xe9! \u1ed4 \u0111i\u1ec7n kh\xf4ng ph\u1ea3i l\xe0 \u0111\u1ed3 ch\u01a1i, tr\xe1nh xa \u1ed5 \u0111i\u1ec7n l\xe0 an to\xe0n nh\u1ea5t.",p,"B\xe9 quay l\u01b0ng l\u1ea1i with \u1ed5 \u0111i\u1ec7n v\xe0 ti\u1ebfp t\u1ee5c ch\u01a1i \u1edf n\u01a1i an to\xe0n. Reward: B\xe9 bi\u1ebft tr\xe1nh xa \u1ed5 \u0111i\u1ec7n! +1 Safety Star.","B\xe9 h\u1ecdc kh\xf4ng ch\u1ea1m tay ho\u1eb7c nh\xe9t v\u1eadt l\u1ea1 v\xe0o \u1ed5 c\u1eafm \u0111i\u1ec7n.",p,1,q,"Ch\u1ecdc thanh s\u1eaft v\xe0o l\u1ed7 xem robot c\xf3 bi\u1ebfn h\xecnh kh\xf4ng.",p,p,"C\u1ea5t thanh s\u1eaft v\xe0o h\u1ed9p \u0111\u1ed3 ch\u01a1i v\xe0 tr\xe1nh xa \u1ed5 \u0111i\u1ec7n.",p,p,"Con c\xf3 \u0111\u01b0\u1ee3c t\u1ef1 \xfd d\xf9ng tay ho\u1eb7c \u0111\u1ed3 v\u1eadt ch\u1ecdc v\xe0o \u1ed5 c\u1eafm \u0111i\u1ec7n kh\xf4ng?","Khi th\u1ea5y \u1ed5 c\u1eafm \u0111i\u1ec7n, con n\xean l\xe0m g\xec?",p,"Tr\u1ebb r\u1ea5t th\xedch kh\xe1m ph\xe1 c\xe1c c\u1ea5u tr\xfac d\u1ea1ng l\u1ed7. H\xe3y s\u1eed d\u1ee5ng n\u1eafp \u0111\u1eady \u1ed5 \u0111i\u1ec7n an to\xe0n cho to\xe0n b\u1ed9 \u1ed5 c\u1eafm t\u1ea7m th\u1ea5p.","B\xe9 \u0111ang c\u1ea7m m\u1ed9t thanh \u0111\u1ed3 ch\u01a1i b\u1eb1ng s\u1eaft nh\u1ecf v\xe0 nh\xecn th\u1ea5y hai l\u1ed7 c\u1ee7a \u1ed5 c\u1eafm \u0111i\u1ec7n tr\xean t\u01b0\u1eddng.",102,"Nh\u1eadn bi\u1ebft m\u1ed1i nguy hi\u1ec3m t\u1eeb d\xf2ng \u0111i\u1ec7n; kh\xf4ng t\u1ef1 \xfd ch\u1ea1m ho\u1eb7c nh\xe9t v\u1eadt l\u1ea1 v\xe0o \u1ed5 c\u1eafm.","An to\xe0n \u0111i\u1ec7n","B\xe0i 2: B\xe0n tay k\u1ef3 di\u1ec7u v\xe0 c\xe1c c\xe1i l\u1ed7","Kh\xf4ng bao gi\u1edd \u0111\u01b0\u1ee3c d\xf9ng tay ho\u1eb7c \u0111\u1ed3 v\u1eadt ch\u1ecdc v\xe0o \u1ed5 \u0111i\u1ec7n con nh\xe9.",p,"Ch\u1ecdc \u0111\u1ed3 kim lo\u1ea1i v\xe0o \u1ed5 \u0111i\u1ec7n c\xf3 th\u1ec3 b\u1ecb \u0111i\u1ec7n gi\u1eadt r\u1ea5t \u0111au v\xe0 r\u1ea5t nguy hi\u1ec3m."),A.pB("Gi\u1ecfi l\u1eafm! B\xe9 \u0111\xe3 nh\u1eadn bi\u1ebft \u0111\u01b0\u1ee3c n\u01b0\u1edbc n\xf3ng nguy hi\u1ec3m v\xe0 kh\xf4ng ngh\u1ecbch n\xfat b\u1ea5m lung tung.",p,"B\xe9 r\u1ee5t tay l\u1ea1i, kh\xf4ng b\u1ea5m n\xfat v\xe0 ch\u1ea1y \u0111i t\xecm m\u1eb9. Reward: B\xe9 kh\xf4ng ngh\u1ecbch thi\u1ebft b\u1ecb n\u01b0\u1edbc n\xf3ng! +1 Safety Star.","B\xe9 h\u1ecdc tr\xe1nh xa b\xecnh th\u1ee7y, n\u01b0\u1edbc n\xf3ng v\xe0 c\xe1c n\xfat b\u1ea5m nguy hi\u1ec3m.",p,1,q,"Nh\u1ea5n th\u1eed c\xe1i n\xfat \u0111\u1ecf xem chuy\u1ec7n g\xec x\u1ea3y ra.",p,p,"Tr\xe1nh xa chi\u1ebfc b\xecnh v\xe0 \u0111i t\xecm m\u1eb9.",p,p,"Khi nh\xecn th\u1ea5y ph\xedch n\u01b0\u1edbc ho\u1eb7c b\xecnh n\u01b0\u1edbc n\xf3ng, con n\xean l\xe0m g\xec?","Khi th\u1ea5y b\xecnh n\u01b0\u1edbc n\xf3ng, con n\xean l\xe0m g\xec?",p,"Tr\u1ebb kh\xf4ng \u0111\u1ecbnh ngh\u1ecbch n\u01b0\u1edbc n\xf3ng, tr\u1ebb ch\u1ec9 th\xedch c\u1ea3m gi\xe1c \u0111\u01b0\u1ee3c \u1ea5n n\xfat ho\u1eb7c g\u1ea1t c\u1ea7n. H\xe3y lu\xf4n b\u1eadt kh\xf3a an to\xe0n tr\u1ebb em tr\xean c\xe1c thi\u1ebft b\u1ecb n\xe0y.","M\u1eb9 v\u1eeba \u0111un n\u01b0\u1edbc xong, chi\u1ebfc b\xecnh th\u1ee7y \u0111i\u1ec7n c\xf3 n\xfat \u0111\u1ecf ph\xe1t s\xe1ng \u0111\u01b0\u1ee3c \u0111\u1eb7t tr\xean b\xe0n th\u1ea5p.",103,"Nh\u1eadn bi\u1ebft m\u1ed1i nguy h\u1ea1i t\u1eeb c\xe1c thi\u1ebft b\u1ecb gia d\u1ee5ng c\xf3 ch\u1ee9a n\u01b0\u1edbc s\xf4i/nhi\u1ec7t \u0111\u1ed9 cao; ki\u1ec1m ch\u1ebf h\xe0nh vi t\xf2 m\xf2 nguy hi\u1ec3m.","An to\xe0n n\u01b0\u1edbc n\xf3ng",'B\xe0i 3: C\u01a1n nghi\u1ec7n "\u1ea5n n\xfat"',"Khi th\u1ea5y b\xecnh n\u01b0\u1edbc n\xf3ng, con tuy\u1ec7t \u0111\u1ed1i kh\xf4ng \u0111\u01b0\u1ee3c t\u1ef1 \xfd \u1ea5n n\xfat hay ngh\u1ecbch ng\u1ee3m nh\xe9.",p,"N\u01b0\u1edbc trong b\xecnh c\u1ef1c k\u1ef3 n\xf3ng, \u1ea5n n\xfat c\xf3 th\u1ec3 l\xe0m n\u01b0\u1edbc s\xf4i tr\xe0n ra g\xe2y b\u1ecfng tay."),A.pB("Qu\xe1 xu\u1ea5t s\u1eafc! C\u1ea3nh gi\xe1c v\xe0 ch\u1ea1y \u0111i t\xecm ng\u01b0\u1eddi l\u1edbn tin c\u1eady l\xe0 c\xe1ch b\u1ea3o v\u1ec7 m\xecnh th\xf4ng minh nh\u1ea5t.","assets/videos/Safety_stranger/correct.mp4","B\xe9 l\xf9i l\u1ea1i, ch\u1ea1y th\u1eb3ng v\xe0o c\u1ed5ng tr\u01b0\u1eddng g\u1ecdi c\xf4 gi\xe1o. Reward: B\xe9 kh\xf4ng m\u1eafc m\u01b0u k\u1ebb x\u1ea5u! +1 Brave Star.","B\xe9 h\u1ecdc c\u1ea3nh gi\xe1c v\u1edbi ng\u01b0\u1eddi l\u1ea1 gi\u1ea3 danh ng\u01b0\u1eddi quen d\xf9 h\u1ecd bi\u1ebft t\xean m\xecnh.","assets/videos/Safety_stranger/Intro.mp4",2,o,"Tin l\u1eddi c\xf4, b\u01b0\u1edbc l\xean xe \xf4 t\xf4 \u0111\u1ec3 v\u1ec1 v\u1edbi m\u1eb9.","assets/images/flashCard/Safety_stranger/Wrong.webp","assets/voices/Safety_stranger/wrong_l3.mp3",'L\xf9i l\u1ea1i, n\xf3i to "Ch\xe1u kh\xf4ng \u0111i!" v\xe0 ch\u1ea1y v\xe0o tr\u01b0\u1eddng b\xe1o c\xf4 gi\xe1o.',"assets/images/flashCard/Safety_stranger/Correct.webp","assets/voices/Safety_stranger/correct_l3.mp3","N\u1ebfu m\u1ed9t ng\u01b0\u1eddi l\u1ea1 g\u1ecdi \u0111\xfang t\xean con v\xe0 b\u1ea3o l\xean xe \u0111\u1ec3 ch\u1edf v\u1ec1 v\u1edbi b\u1ed1 m\u1eb9, con c\xf3 \u0111i theo kh\xf4ng?","Ng\u01b0\u1eddi l\u1ea1 n\xf3i m\u1eb9 nh\u1edd \u0111\u1ebfn \u0111\xf3n. Con s\u1ebd x\u1eed l\xfd th\u1ebf n\xe0o?","assets/voices/Safety_stranger/question_l3.mp3","B\xe9 r\u1ea5t d\u1ec5 m\u1ea5t c\u1ea3nh gi\xe1c khi ng\u01b0\u1eddi l\u1ea1 \u0103n m\u1eb7c \u0111\u1eb9p, t\u1ecf ra th\xe2n thi\u1ec7n v\xe0 bi\u1ebft r\xf5 t\xean b\xe9.","M\u1ed9t ng\u01b0\u1eddi ph\u1ee5 n\u1eef l\u1ea1 m\u1eb7t \u0111i \xf4 t\xf4 \u0111\u1ebfn c\u1ed5ng tr\u01b0\u1eddng, g\u1ecdi \u0111\xfang t\xean b\xe9 v\xe0 n\xf3i m\u1eb9 nh\u1edd \u0111\xf3n.",201,"C\u1ea3nh gi\xe1c v\u1edbi ng\u01b0\u1eddi l\u1ea1 gi\u1ea3 danh ng\u01b0\u1eddi quen.","K\u1ef9 n\u0103ng \u0111\u1ed1i ph\xf3 k\u1ebb gian tinh vi",'B\xe0i 1: Ng\u01b0\u1eddi l\u1ea1 "bi\u1ebft t\xean b\xe9"',"Tuy\u1ec7t \u0111\u1ed1i kh\xf4ng \u0111i theo ng\u01b0\u1eddi l\u1ea1 d\xf9 h\u1ecd bi\u1ebft t\xean con.","assets/videos/Safety_stranger/wrong.mp4","K\u1ebb x\u1ea5u c\xf3 th\u1ec3 gi\u1ea3 v\u1edd quen bi\u1ebft m\u1eb9 \u0111\u1ec3 l\u1eeba b\u1eaft c\xf3c con."),A.pB("Tuy\u1ec7t v\u1eddi! Bi\u1ebft n\xf3i kh\xf4ng v\u1edbi tr\xf2 ch\u01a1i nguy hi\u1ec3m ch\u1ee9ng t\u1ecf con r\u1ea5t tr\u01b0\u1edfng th\xe0nh.",p,"B\xe9 n\xf3i kh\xf4ng, ch\u1ea1y \u0111i g\u1ecdi ng\u01b0\u1eddi l\u1edbn l\u1ea5y b\xf3ng gi\xfap. Reward: B\xe9 bi\u1ebft n\xf3i kh\xf4ng v\u1edbi nguy hi\u1ec3m! +1 Shield Star.","B\xe9 h\u1ecdc t\u1eeb ch\u1ed1i \xe1p l\u1ef1c b\u1ea1n b\xe8 v\xe0 kh\xf4ng l\xe0m vi\u1ec7c nguy hi\u1ec3m \u0111\u1ec3 ch\u1ee9ng t\u1ecf b\u1ea3n th\xe2n.",p,2,o,"Tr\xe8o r\xe0o sang l\u1ea5y b\xf3ng \u0111\u1ec3 ch\u1ee9ng t\u1ecf m\xecnh kh\xf4ng nh\xe1t gan.",p,p,"Ki\xean quy\u1ebft t\u1eeb ch\u1ed1i v\xe0 \u0111i t\xecm ng\u01b0\u1eddi l\u1edbn nh\u1edd l\u1ea5y gi\xfap.",p,p,"N\u1ebfu b\u1ecb b\u1ea1n b\xe8 r\u1ee7 r\xea ho\u1eb7c th\xe1ch th\u1ee9c ch\u01a1i m\u1ed9t tr\xf2 nguy hi\u1ec3m, con c\xf3 l\xe0m theo kh\xf4ng?","Khi b\u1ea1n \xe9p con l\xe0m m\u1ed9t vi\u1ec7c nguy hi\u1ec3m, con n\xean l\xe0m g\xec?",p,"\u1ede \u0111\u1ed9 tu\u1ed5i n\xe0y, b\xe9 r\u1ea5t s\u1ee3 b\u1ecb b\u1ea1n b\xe8 ch\xea c\u01b0\u1eddi ho\u1eb7c t\u1ea9y chay, n\xean d\u1ec5 nh\u1eafm m\u1eaft l\xe0m li\u1ec1u.","B\u1ea1n b\xe8 x\xfai b\xe9 tr\xe8o r\xe0o sang s\xe2n nh\xe0 h\xe0ng x\xf3m c\xf3 ch\xf3 d\u1eef \u0111\u1ec3 nh\u1eb7t b\xf3ng.",202,"T\u1eeb ch\u1ed1i \xe1p l\u1ef1c b\u1ea1n b\xe8 v\xe0 kh\xf4ng l\xe0m vi\u1ec7c nguy hi\u1ec3m \u0111\u1ec3 ch\u1ee9ng t\u1ecf b\u1ea3n th\xe2n.","K\u1ef9 n\u0103ng \u0111\u1ed1i m\u1eb7t \xe1p l\u1ef1c \u0111\u1ed3ng trang l\u1ee9a","B\xe0i 2: L\u1eddi th\xe1ch \u0111\u1ed1 c\u1ee7a b\u1ea1n b\xe8","Kh\xf4ng ai c\xf3 quy\u1ec1n \xe9p con l\xe0m vi\u1ec7c nguy hi\u1ec3m. T\u1eeb ch\u1ed1i l\u1eddi th\xe1ch \u0111\u1ed1 d\u1ea1i d\u1ed9t m\u1edbi l\xe0 b\u1ea3n l\u0129nh.",p,"C\u1ed1 ch\u1ee9ng t\u1ecf b\u1ea3n th\xe2n b\u1eb1ng c\xe1ch l\xe0m vi\u1ec7c nguy hi\u1ec3m kh\xf4ng ph\u1ea3i l\xe0 d\u0169ng c\u1ea3m."),A.pB("R\u1ea5t \u0111\xe1ng t\u1ef1 h\xe0o! S\u1ef1 trung th\u1ef1c c\u1ee7a con \u0111\xe1ng gi\xe1 h\u01a1n b\u1ea5t k\u1ef3 m\xf3n \u0111\u1ed3 ch\u01a1i n\xe0o.",p,"B\xe9 nh\u1eb7t v\xed ch\u1ea1y theo \u0111\u01b0a t\u1eadn tay ng\u01b0\u1eddi \u0111\xe1nh r\u01a1i. Reward: B\xe9 l\xe0 em b\xe9 trung th\u1ef1c! +1 Honesty Star.","B\xe9 h\u1ecdc ki\u1ec3m so\xe1t c\xe1m d\u1ed7 v\xe0 trung th\u1ef1c tr\u1ea3 l\u1ea1i \u0111\u1ed3 kh\xf4ng ph\u1ea3i c\u1ee7a m\xecnh.",p,2,o,"L\xe9n nh\u1eb7t chi\u1ebfc v\xed gi\u1ea5u v\xe0o t\xfai qu\u1ea7n \u0111\u1ec3 mang v\u1ec1.",p,p,"Nh\u1eb7t l\xean v\xe0 g\u1ecdi ng\u01b0\u1eddi \u0111\xe1nh r\u01a1i \u0111\u1ec3 tr\u1ea3 l\u1ea1i.",p,p,"N\u1ebfu nh\u1eb7t \u0111\u01b0\u1ee3c chi\u1ebfc v\xed ho\u1eb7c \u0111\u1ed3 ch\u01a1i c\u1ee7a ng\u01b0\u1eddi kh\xe1c \u0111\xe1nh r\u01a1i, con s\u1ebd l\xe0m g\xec?","Nh\u1eb7t \u0111\u01b0\u1ee3c \u0111\u1ed3 kh\xf4ng ph\u1ea3i c\u1ee7a m\xecnh, con n\xean l\xe0m g\xec?",p,'B\xe9 d\u1ec5 b\u1ecb c\xe1m d\u1ed7 b\u1edfi suy ngh\u0129 "Kh\xf4ng ai nh\xecn th\u1ea5y th\xec kh\xf4ng sao".',"B\xe9 th\u1ea5y m\u1ed9t ng\u01b0\u1eddi \u0111i tr\u01b0\u1edbc l\xe0m r\u01a1i chi\u1ebfc v\xed c\xf3 nhi\u1ec1u ti\u1ec1n trong khu vui ch\u01a1i.",203,"V\u01b0\u1ee3t qua l\xf2ng tham, trung th\u1ef1c tr\u1ea3 l\u1ea1i c\u1ee7a r\u01a1i.","K\u1ef9 n\u0103ng ki\u1ec3m so\xe1t c\xe1m d\u1ed7 v\xe0 trung th\u1ef1c","B\xe0i 3: Chi\u1ebfc v\xed b\u1ecb \u0111\xe1nh r\u01a1i","\u0110\u1ed3 kh\xf4ng ph\u1ea3i c\u1ee7a m\xecnh th\xec tuy\u1ec7t \u0111\u1ed1i kh\xf4ng \u0111\u01b0\u1ee3c l\u1ea5y, d\xf9 kh\xf4ng ai th\u1ea5y con nh\xe9.",p,"L\u1ea5y \u0111\u1ed3 c\u1ee7a ng\u01b0\u1eddi kh\xe1c s\u1ebd l\xe0m h\u1ecd bu\u1ed3n kh\u1ed5 v\xe0 ch\xednh con c\u0169ng c\u1ea3m th\u1ea5y t\u1ed9i l\u1ed7i."),A.pB("Gi\u1ecfi l\u1eafm! Ch\xfang ta lu\xf4n ch\u1edd \u0111\xe8n xanh \u0111\u1ec3 qua \u0111\u01b0\u1eddng an to\xe0n.","assets/videos/Crossroad/correct.mp4","B\xe9 \u0111\u1ee9ng c\u1ea1nh m\u1eb9, ch\u1edd \u0111\xe8n xanh r\u1ed3i hai m\u1eb9 con n\u1eafm tay qua \u0111\u01b0\u1eddng. Reward: B\xe9 bi\u1ebft ch\u1edd \u0111\xe8n xanh! +1 Safety Star.","B\xe9 h\u1ecdc ch\u1edd \u0111\xe8n xanh, n\u1eafm tay ng\u01b0\u1eddi l\u1edbn v\xe0 quan s\xe1t khi qua \u0111\u01b0\u1eddng.","assets/videos/Crossroad/intro.mp4",3,n,"Ch\u1ea1y nhanh qua \u0111\u01b0\u1eddng.","assets/images/flashCard/Crossroad/Wrong.webp","assets/voices/Crossroad/wrong.mp3","\u0110\u1ee9ng l\u1ea1i ch\u1edd \u0111\xe8n xanh.","assets/images/flashCard/Crossroad/Correct.webp","assets/voices/Crossroad/correct.mp3","\u0110\xe8n m\xe0u g\xec th\xec m\xecnh m\u1edbi \u0111\u01b0\u1ee3c \u0111i qua \u0111\u01b0\u1eddng h\u1ea3 con?","Xe \u0111ang ch\u1ea1y r\u1ea5t \u0111\xf4ng. Con n\xean l\xe0m g\xec tr\u01b0\u1edbc khi qua \u0111\u01b0\u1eddng?","assets/voices/Crossroad/Question.mp3","B\xe9 v\u1eabn hay qu\xean nh\xecn hai b\xean tr\u01b0\u1edbc khi qua \u0111\u01b0\u1eddng.","B\xe9 \u0111i b\u1ed9 c\xf9ng m\u1eb9, ph\xeda b\xean kia \u0111\u01b0\u1eddng c\xf3 ti\u1ec7m kem nh\u01b0ng \u0111\xe8n giao th\xf4ng \u0111ang m\xe0u \u0111\u1ecf.",301,"Bi\u1ebft ch\u1edd \u0111\xe8n xanh tr\u01b0\u1edbc khi qua \u0111\u01b0\u1eddng.","An to\xe0n giao th\xf4ng","B\xe0i 1: Qua \u0111\u01b0\u1eddng an to\xe0n","Khi qua \u0111\u01b0\u1eddng, m\xecnh ph\u1ea3i ch\u1edd \u0111\xe8n xanh v\xe0 nh\xecn hai b\xean.","assets/videos/Crossroad/wrong.mp4","Qua \u0111\u01b0\u1eddng khi \u0111\xe8n \u0111\u1ecf r\u1ea5t nguy hi\u1ec3m v\xec xe c\xf3 th\u1ec3 kh\xf4ng d\u1eebng k\u1ecbp."),A.pB("Gi\u1ecfi l\u1eafm! Nh\u1edd ng\u01b0\u1eddi l\u1edbn gi\xfap \u0111\u1ee1 l\xe0 c\xe1ch an to\xe0n nh\u1ea5t.",p,"B\xe9 g\u1eb7p c\xf4 nh\xe2n vi\xean, c\xf4 ph\xe1t loa v\xe0 m\u1eb9 t\xecm th\u1ea5y b\xe9. Reward: B\xe9 bi\u1ebft x\u1eed l\xfd khi b\u1ecb l\u1ea1c! +1 Safety Star.","B\xe9 h\u1ecdc \u0111\u1ee9ng y\xean v\xe0 t\xecm ng\u01b0\u1eddi l\u1edbn \u0111\xe1ng tin c\u1eady khi b\u1ecb l\u1ea1c.",p,3,n,"Ch\u1ea1y \u0111i t\xecm m\u1eb9 kh\u1eafp n\u01a1i.",p,p,"\u0110\u1ee9ng y\xean v\xe0 t\xecm nh\xe2n vi\xean gi\xfap \u0111\u1ee1.",p,p,"N\u1ebfu ch\u1eb3ng may b\u1ecb l\u1ea1c m\u1ea5t b\u1ed1 m\u1eb9 trong si\xeau th\u1ecb, con n\xean l\xe0m g\xec?","N\u1ebfu b\u1ecb l\u1ea1c trong si\xeau th\u1ecb, con n\xean l\xe0m g\xec?",p,"B\xe9 v\u1eabn ch\u1ecdn ch\u1ea1y \u0111i t\xecm m\u1eb9 khi b\u1ecb l\u1ea1c.","B\xe9 \u0111ang \u0111i si\xeau th\u1ecb c\xf9ng m\u1eb9, quay l\u1ea1i nh\xecn \u0111\u1ed3 ch\u01a1i r\u1ed3i kh\xf4ng th\u1ea5y m\u1eb9 \u0111\xe2u.",302,"Bi\u1ebft t\xecm ng\u01b0\u1eddi gi\xfap \u0111\u1ee1 khi b\u1ecb l\u1ea1c.","X\u1eed l\xfd khi b\u1ecb l\u1ea1c","B\xe0i 2: B\u1ecb l\u1ea1c trong si\xeau th\u1ecb","N\u1ebfu b\u1ecb l\u1ea1c, h\xe3y \u0111\u1ee9ng y\xean v\xe0 t\xecm ng\u01b0\u1eddi l\u1edbn \u0111\xe1ng tin c\u1eady.",p,"Ch\u1ea1y lung tung c\xf3 th\u1ec3 l\xe0m m\xecnh l\u1ea1c xa h\u01a1n."),A.pB("Gi\u1ecfi l\u1eafm! Khi g\u1eb7p n\u01a1i nguy hi\u1ec3m, h\xe3y nh\u1edd ng\u01b0\u1eddi l\u1edbn gi\xfap \u0111\u1ee1.",p,"B\xe9 ch\u1ea1y t\u1edbi ch\xfa b\u1ea3o v\u1ec7 nh\u1edd l\u1ea5y b\xf3ng gi\xfap. Reward: B\xe9 bi\u1ebft tr\xe1nh xa h\u1ed3 n\u01b0\u1edbc s\xe2u! +1 Safety Star.","B\xe9 h\u1ecdc tr\xe1nh xa h\u1ed3 n\u01b0\u1edbc s\xe2u v\xe0 t\xecm ng\u01b0\u1eddi l\u1edbn gi\xfap \u0111\u1ee1 khi g\u1eb7p nguy hi\u1ec3m.",p,3,n,"T\u1ef1 ch\u1ea1y l\u1ea1i l\u1ea5y b\xf3ng.",p,p,"T\xecm ng\u01b0\u1eddi l\u1edbn gi\xfap \u0111\u1ee1.",p,p,"N\u1ebfu \u0111\u1ed3 ch\u01a1i b\u1ecb r\u01a1i xu\u1ed1ng h\u1ed3 n\u01b0\u1edbc s\xe2u, con n\xean l\xe0m g\xec?","N\u1ebfu \u0111\u1ed3 ch\u01a1i r\u01a1i xu\u1ed1ng h\u1ed3 n\u01b0\u1edbc, con n\xean l\xe0m g\xec?",p,"B\xe9 v\u1eabn c\xf3 xu h\u01b0\u1edbng t\u1ef1 \u0111\u1ebfn g\u1ea7n m\xe9p n\u01b0\u1edbc.","B\xe9 \u0111\xe1 b\xf3ng trong c\xf4ng vi\xean g\u1ea7n h\u1ed3 n\u01b0\u1edbc, qu\u1ea3 b\xf3ng l\u0103n xu\u1ed1ng g\u1ea7n m\xe9p h\u1ed3.",303,"Bi\u1ebft t\xecm ng\u01b0\u1eddi l\u1edbn gi\xfap \u0111\u1ee1 khi g\u1eb7p nguy hi\u1ec3m.","An to\xe0n g\u1ea7n n\u01b0\u1edbc","B\xe0i 3: H\u1ed3 n\u01b0\u1edbc / h\u1ed3 b\u01a1i","N\u1ebfu \u0111\u1ed3 ch\u01a1i r\u01a1i xu\u1ed1ng n\u01b0\u1edbc, m\xecnh ph\u1ea3i t\xecm ng\u01b0\u1eddi l\u1edbn gi\xfap \u0111\u1ee1.",p,"Ch\u01a1i g\u1ea7n h\u1ed3 n\u01b0\u1edbc m\u1ed9t m\xecnh r\u1ea5t nguy hi\u1ec3m v\xe0 c\xf3 th\u1ec3 b\u1ecb tr\u01b0\u1ee3t ch\xe2n.")],A.az("G<io>"))})
